module model_compare_counter_core #(
    parameter integer COUNT_WIDTH = 8,
    parameter integer STEP_WIDTH  = 4
) (
    input  logic                    clk,
    input  logic                    rst_n,
    input  logic                    enable,
    input  logic                    clear,
    input  logic [STEP_WIDTH-1:0]   step,
    output logic [COUNT_WIDTH-1:0]  count,
    output logic                    wrapped,
    output logic                    valid
);

    // Architectural state variables from function_model.state_variables.
    logic [COUNT_WIDTH-1:0] count_q;
    logic                   wrapped_q;
    logic                   valid_q;

    // FSM states from fsm.control.states.
    localparam [1:0] RESET  = 2'd0;
    localparam [1:0] CLEAR  = 2'd1;
    localparam [1:0] UPDATE = 2'd2;
    localparam [1:0] IDLE   = 2'd3;

    logic [1:0] state_q;
    logic [1:0] state_d;

    // Zero-extended step and adder for modulo-256 update plus overflow carry.
    logic [COUNT_WIDTH-1:0] step_ext;
    logic [COUNT_WIDTH:0]   sum_ext;

    // Output-rule aliases (function_model output naming).
    logic [COUNT_WIDTH-1:0] out_count;
    logic                   out_wrapped;
    logic                   out_valid;

    assign step_ext = {{(COUNT_WIDTH-STEP_WIDTH){1'b0}}, step};
    assign sum_ext  = {1'b0, count_q} + {1'b0, step_ext};

    // Conventional next-state decode implementing SSOT FSM transitions.
    always @(*) begin
        state_d = state_q;
        case (state_q)
            RESET: begin
                state_d = IDLE;
            end
            IDLE: begin
                if (clear) begin
                    state_d = CLEAR;
                end else if (enable) begin
                    state_d = UPDATE;
                end else begin
                    state_d = IDLE;
                end
            end
            UPDATE: begin
                state_d = IDLE;
            end
            CLEAR: begin
                state_d = IDLE;
            end
            default: begin
                state_d = IDLE;
            end
        endcase
    end

    // State register with async assert / sync deassert reset behavior.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state_q <= RESET;
        end else begin
            state_q <= state_d;
        end
    end

    // latency=1 datapath commit: clear priority over enable on the accepting edge.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            count_q   <= {COUNT_WIDTH{1'b0}};
            wrapped_q <= 1'b0;
            valid_q   <= 1'b0;
        end else if (clear) begin
            // FM_CLEAR
            count_q   <= {COUNT_WIDTH{1'b0}};
            wrapped_q <= 1'b0;
            valid_q   <= 1'b0;
        end else if (enable) begin
            // FM_UPDATE: modulo update and overflow pulse from carry-out.
            count_q   <= sum_ext[COUNT_WIDTH-1:0];
            wrapped_q <= sum_ext[COUNT_WIDTH];
            valid_q   <= 1'b1;
        end else begin
            // FM_IDLE: hold count and deassert one-cycle pulses.
            count_q   <= count_q;
            wrapped_q <= 1'b0;
            valid_q   <= 1'b0;
        end
    end

    assign out_count   = count_q;
    assign out_wrapped = wrapped_q;
    assign out_valid   = valid_q;

    assign count   = out_count;
    assign wrapped = out_wrapped;
    assign valid   = out_valid;

endmodule

